-- LeadFlow AI reference schema. The deployed project is already provisioned.
create table if not exists leadflow_leads (id bigint generated by default as identity primary key,name text not null,phone text not null,email text,source text not null,service text not null,estimated_value numeric not null default 0,status text not null default 'New',outcome text not null default 'Pending',response_seconds integer not null default 0,created_at timestamptz not null default now());
create table if not exists leadflow_niches (id bigint generated by default as identity primary key,slug text not null,name text not null,eyebrow text not null,headline text not null,description text not null,avg_lead_value numeric not null);
create table if not exists leadflow_conversions (id bigint generated by default as identity primary key,type text not null,name text not null,email text not null,phone text,company text,plan text,message text,calculator_data jsonb default '{}'::jsonb,status text not null default 'New',created_at timestamptz not null default now());
create table if not exists leadflow_settings (id bigint generated by default as identity primary key,missed_call_enabled boolean not null default true,sms_template text not null,webhook_url text not null,widget_color text not null,widget_greeting text not null,updated_at timestamptz not null default now());
create table if not exists leadflow_referrals (id bigint generated by default as identity primary key,name text not null,email text not null,status text not null default 'Invited',credit numeric not null default 0,created_at timestamptz not null default now());
create table if not exists leadflow_messages (id bigint generated by default as identity primary key,lead_id bigint,channel text not null,direction text not null,from_number text,to_number text,body text not null,provider_sid text,created_at timestamptz not null default now());
create table if not exists leadflow_subscriptions (id bigint generated by default as identity primary key,provider_subscription_id text unique not null,customer_email text,product_id text,status text not null,updated_at timestamptz not null default now());
create table if not exists leadflow_webhook_events (id bigint generated by default as identity primary key,event_id text unique not null,event_type text not null,payload jsonb not null,created_at timestamptz not null default now());
create index if not exists leadflow_leads_phone_idx on leadflow_leads(phone);
create index if not exists leadflow_messages_lead_idx on leadflow_messages(lead_id,created_at desc);
